#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, M; scanf("%d %d", &N, &M);
        char *seen = (char*)calloc(M+1, sizeof(char));
        int distinct = 0;
        for(int i=0;i<N;i++){
            int x; scanf("%d", &x);
            if(!seen[x]){ seen[x]=1; distinct++; }
        }
        free(seen);
        if(distinct < M) printf("Yes\n"); else printf("No\n");
    }
    return 0;
}

